// packages/core/src/components/Alert/Alert.test.tsx
import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { Alert, type AlertProps } from './Alert';

const renderAlert = (props?: Partial<AlertProps>) => {
  const { children, ...rest } = props ?? {};

  return render(
    <Alert title="Heads up" {...rest}>
      {children ?? 'Additional information to keep everyone aligned.'}
    </Alert>
  );
};

describe('Alert', () => {
  describe('role semantics', () => {
    const roleCases: ReadonlyArray<{ variant: AlertProps['variant']; role: string }> = [
      { variant: 'info', role: 'status' },
      { variant: 'danger', role: 'alert' }
    ];

    it.each(roleCases)('sets %s variant role to %s', ({ variant, role }) => {
      const { container } = renderAlert({ variant });
      const root = container.firstElementChild as HTMLElement;
      expect(root.getAttribute('role')).toBe(role);
    });
  });

  describe('variants', () => {
    const variantCases: ReadonlyArray<{
      variant: AlertProps['variant'];
      tokens: readonly [string, string];
    }> = [
      {
        variant: 'success',
        tokens: ['bg-gradient-utility-success', 'fill-color-content-utility-success-strong']
      },
      {
        variant: 'info',
        tokens: ['bg-gradient-utility-info', 'fill-color-content-utility-info-strong']
      },
      {
        variant: 'warning',
        tokens: ['bg-gradient-utility-warning', 'fill-color-content-utility-warning-strong']
      },
      {
        variant: 'danger',
        tokens: ['bg-gradient-utility-danger', 'fill-color-content-utility-danger-strong']
      }
    ];

    it.each(variantCases)('applies %s variant surface and icon tokens', ({ variant, tokens }) => {
      const { container } = renderAlert({ variant });
      const root = container.firstElementChild as HTMLElement;
      const icon = container.querySelector('[data-slot="icon"]');
      const aggregated = `${root.className} ${icon?.getAttribute('class') ?? ''}`;
      const hasTokens = tokens.every(token => aggregated.includes(token));
      expect(hasTokens).toBe(true);
    });
  });

  it('renders only the title when description is absent', () => {
    const { container } = render(
      <Alert title="Primary message" isDismissible={false} withIcon={false} />
    );
    const titleSlot = container.querySelector('[data-slot="title"]');
    const descriptionSlot = container.querySelector('[data-slot="description"]');
    expect(Boolean(titleSlot) && !descriptionSlot).toBe(true);
  });

  it('renders only the description when title is absent', () => {
    const { container } = render(
      <Alert isDismissible={false} withIcon={false}>
        Description only copy.
      </Alert>
    );
    const titleSlot = container.querySelector('[data-slot="title"]');
    const descriptionSlot = container.querySelector('[data-slot="description"]');
    expect(Boolean(descriptionSlot) && !titleSlot).toBe(true);
  });

  it('omits the icon slot when withIcon is false', () => {
    const { container } = renderAlert({ withIcon: false });
    const icon = container.querySelector('[data-slot="icon"]');
    expect(icon).toBeNull();
  });

  it('omits the close button when isDismissible is false', () => {
    const { container } = renderAlert({ isDismissible: false });
    const closeButton = container.querySelector('[data-slot="closeIcon"]');
    expect(closeButton).toBeNull();
  });

  it('invokes onCloseClick when the dismiss control is activated', async () => {
    const user = userEvent.setup();
    const handleClose = jest.fn();
    renderAlert({ onCloseClick: handleClose });
    await user.click(screen.getByLabelText('Dismiss alert'));
    expect(handleClose).toHaveBeenCalledTimes(1);
  });

  it('renders the text link slot with passthrough props', () => {
    renderAlert({
      textLink: {
        href: '#docs',
        label: 'Read docs',
        variant: 'inverted'
      }
    });
    const link = screen.getByRole('link', { name: 'Read docs' });
    expect(link).toHaveAttribute('href', '#docs');
  });

  it('sets an accessible label on the dismiss control', () => {
    renderAlert();
    const closeButton = screen.getByRole('button', { name: 'Dismiss alert' });
    expect(closeButton.getAttribute('aria-label')).toBe('Dismiss alert');
  });

  it('renders a custom closeIcon when provided', () => {
    const CustomIcon = () => <svg data-testid="custom-close" />;
    renderAlert({ closeIcon: <CustomIcon /> });
    expect(screen.getByTestId('custom-close')).toBeInTheDocument();
  });
});
